def main():
    data = json.loads(DATA_PATH.read_text(encoding="utf-8-sig"))
    analysis = next(item for item in data["analysis"] if int(item["year"]) == 112)
    for question in analysis["questions"]:
        no = int(question["no"])
        if no in SOLUTIONS:
            question["solution"] = SOLUTIONS[no]
            question["commonMistakes"] = "常見錯誤：只背答案而沒有列出判斷依據；計算題未先寫物理關係式，或把單位、方向、有效位數與適用條件混在一起。"
            question["keyConcept"] = "關鍵觀念：先辨認物理模型，再用守恆律、受力/力矩、波動條件、電磁感應或量測不確定度等基本關係逐步推論。"
    DATA_PATH.write_text(
        "\ufeff" + json.dumps(data, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )


if __name__ == "__main__":
    main()
